+      requiresAck: true,
+      ttlMs: this.config.taskTimeoutMs,
+    });
+
+    const duration = performance.now() - startTime;
+    this.recordCoordinationLatency(duration);
+
+    this.emitEvent('task.assigned', {
+      taskId,
+      agentId: agent.id.id,
+      domain,
