+
+      return {
+        taskId,
+        domain,
+        success: result.status === 'completed',
+        result: result.output,
+        durationMs: performance.now() - startTime,
+      };
+    } catch (error) {
+      return {
+        taskId,
+        domain,
+        success: false,
+        error: error instanceof Error ? error : new Error(String(error)),
+        durationMs: performance.now() - startTime,
+      };
+    }
+  }
